#include <bits/stdc++.h>
using namespace std;

void solve() {
    string s;
    cin >> s;

    vector<int> freq(26, 0);
    for(char c : s) {
        freq[c - 'a']++;
    }

    int odd_count = 0;
    for(int i = 0; i < 26; i++) {
        if(freq[i] % 2 != 0) {
            odd_count++;
        }
    }

    if(odd_count <= 1) {
        cout << "YES\n";
    } else {
        cout << "NO\n";
    }
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        solve();
    }
    return 0;
}
